import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useDdmhListFilterState } from '../../../hooks/useDdmhListFilterState';
import { useDdmhPermissions } from '../../../hooks/useDdmhPermissions';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { PurchaseOrderDto } from '../../../services/mh/models';
import { PO_STATUS_OPTIONS } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { ddmhPageLabels } from '../../../constants/ddmhPageLabels';
import { MH_PATHS } from '../../../appPaths';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { WmsSchemaListGrid } from '../../../components/list/WmsSchemaListGrid';
import {
  VoucherRowActionMenu,
  type VoucherRowMenuAction,
} from '../../../components/voucher-list/VoucherRowActionMenu';
import { buildPurchasingListToolbar } from '../../../features/mh/purchasingListToolbar';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-mh-ddmh';
const PAGE_ID = 'mh-ddmh';

const DdmhListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const { canCreate, canConfirm, canWrite } = useDdmhPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useDdmhListFilterState(LIST_FILTER_SCOPE.ddmh);

  const [items, setItems] = useState<PurchaseOrderDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSize] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: PurchaseOrderDto } | null>(null);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
    selection.clearActiveRow();
  }, [selection]);

  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
    selection.clearActiveRow();
  }, [searchDraft, setSearch, resetPage, selection]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const activeRow = selection.activeRow;

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getOrders({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        search: search || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, ddmhPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, page, pageSize, search, dispatch, reloadKey]);

  const handleConfirm = useCallback(async (id: string) => {
    try {
      await purchasingService.confirmOrder(id);
      dispatchAppToast(dispatch, { message: ddmhPageLabels.confirmSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, ddmhPageLabels.confirmError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const navigateToRow = useCallback((id: string, edit?: boolean) => {
    if (edit) navigate(`${MH_PATHS.ddmhThem}?editId=${id}`);
    else navigate(MH_PATHS.ddmhDetail(id));
  }, [navigate]);

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          navigateToRow(row.id);
          break;
        case 'edit':
          if (row.status === 'Draft' && canWrite) navigateToRow(row.id, true);
          break;
        default:
          break;
      }
    },
    [rowMenu, navigateToRow, canWrite],
  );

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow?.status === 'Draft' && canWrite;
  const canConfirmActive = activeRow?.status === 'Draft' && canConfirm;

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'voucher' as const,
      actions: buildPurchasingListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: refresh,
        onEditConfig: () => setShowSchemaEditor(true),
        canCreate,
        onCreate: () => navigate(MH_PATHS.ddmhThem),
        canView: canViewActive,
        onView: () => activeRow && navigateToRow(activeRow.id),
        canEdit: canEditActive,
        onEdit: () => activeRow && navigateToRow(activeRow.id, true),
        canApprove: canConfirmActive,
        onApprove: () => activeRow && handleConfirm(activeRow.id),
        approveLabel: 'Xác nhận',
      }),
    }),
    [
      refresh,
      canCreate,
      canViewActive,
      canEditActive,
      canConfirmActive,
      activeRow,
      navigate,
      navigateToRow,
      handleConfirm,
    ],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            placeholder="Số đơn, NCC, mô tả…"
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => { setStatus(e.target.value); resetPage(); }}
            options={PO_STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-filter-status`}
          />
        ),
      },
    ],
    [
      fromDate,
      toDate,
      datePreset,
      searchDraft,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
    ],
  );

  const listBody = (
    <WmsSchemaListGrid
      catalogKind={LIST_UI_SCHEMA_KIND.purchaseOrder}
      testIdPrefix={TEST_ID}
      rows={items}
      page={page}
      pageSize={pageSize}
      showTableLoading={showTableLoading}
      viewMobile={viewMobile}
      emptyLabel={ddmhPageLabels.empty}
      selection={selection}
      onRowDoubleClick={r => navigateToRow(r.id)}
      onRowOpenActionMenu={({ row, x, y }) => {
        selection.selectActiveRow(row);
        setRowMenu({ x, y, row });
      }}
    />
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: ddmhPageLabels.listTitle,
          titleIconClass: 'fas fa-shopping-cart',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={ddmhPageLabels.listSubtitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={(
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearActiveRow(); }}
            onPageSizeChange={size => {
              setPageSize(size as ListPageSize);
              setPage(1);
              selection.clearActiveRow();
            }}
          />
        )}
        modals={(
          <>
            <ListUiSchemaEditorModal
              testIdPrefix={TEST_ID}
              catalogKind={LIST_UI_SCHEMA_KIND.purchaseOrder}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => { setReloadKey(k => k + 1); }}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView
              showEdit={rowMenu?.row.status === 'Draft' && canWrite}
              showViewLedger={false}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default DdmhListPage;
